j=A.b(["\u0412\u0445\u043e\u0434 \u0447\u0435\u0440\u0435\u0437 Telegram: \u0432\u0441\u044f \u0432\u0430\u0448\u0430 \u0430\u0443\u0434\u0438\u0442\u043e\u0440\u0438\u044f \u0443\u0436\u0435 \u0442\u0430\u043c, \u043d\u0438 \u043f\u0430\u0440\u043e\u043b\u0435\u0439, \u043d\u0438 \u043f\u043e\u0447\u0442\u044b.","\u0424\u043e\u0440\u043c\u0443\u043b\u0438\u0440\u043e\u0432\u043a\u0430 \xab\u0441\u043e\u0445\u0440\u0430\u043d\u0438\u043c \u0432\u0430\u0448 \u043f\u0443\u0442\u044c\xbb \u2014 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044f \u043a\u0430\u043a \u0437\u0430\u0431\u043e\u0442\u0430, \u0430 \u043d\u0435 \u0431\u0430\u0440\u044c\u0435\u0440."],k)
p=A.b(["\u041a\u0430\u0436\u0434\u044b\u0439 \u0432\u043e\u0448\u0435\u0434\u0448\u0438\u0439 \u2014 \u043a\u043e\u043d\u0442\u0430\u043a\u0442 \u0432 \u0432\u0430\u0448\u0435\u0439 \u0431\u0430\u0437\u0435 \u0441 \u0432\u044b\u0431\u0440\u0430\u043d\u043d\u044b\u043c\u0438 \u0442\u0435\u043c\u0430\u043c\u0438: \u043e\u0441\u043d\u043e\u0432\u0430 \u0434\u043b\u044f \u043f\u0443\u0448\u0435\u0439 \u0438 \u0441\u0435\u0433\u043c\u0435\u043d\u0442\u0430\u0446\u0438\u0438.","\u0421\u0442\u0435\u043d\u0430 \u043b\u043e\u0433\u0438\u043d\u0430 \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 \u0441\u0440\u0435\u0437\u0430\u0435\u0442 \u043a\u043e\u043d\u0432\u0435\u0440\u0441\u0438\u044e \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u043d\u0430 \u0437\u0434\u0435\u0441\u044c, \u0442\u0440\u0435\u0442\u044c\u0438\u043c \u044d\u043a\u0440\u0430\u043d\u043e\u043c."],k)
p=A.qN(A.b(["Telegram + \u0442\u0435\u043b\u0435\u0444\u043e\u043d \u2014 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0438\u043b\u0438 \u043d\u0443\u0436\u043d\u0430 \u0435\u0449\u0451 \u043f\u043e\u0447\u0442\u0430?","\u0423\u0437\u043d\u0430\u0432\u0430\u0442\u044c \u043f\u043e \u043d\u043e\u043c\u0435\u0440\u0443 \u0442\u0435\u0445, \u043a\u0442\u043e \u0443\u0436\u0435 \u043f\u043e\u043a\u0443\u043f\u0430\u043b \u0432\u0430\u0448\u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u044b, \u0438 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0442\u044c \u0438\u043c \u0434\u043e\u0441\u0442\u0443\u043f \u0441\u0440\u0430\u0437\u0443?"],k),B.oi,j,B.c5,"\u0412\u0445\u043e\u0434","\u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044f: \u043b\u0451\u0433\u043a\u0438\u0439 \u0432\u0445\u043e\u0434","\u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044f \u0432 \u043e\u0434\u0438\u043d \u0442\u0430\u043f \u2014 \u043f\u043e\u0441\u043b\u0435 \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0443\u0436\u0435 \u0443\u0432\u0438\u0434\u0435\u043b \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u0434\u043e.",p)
j=A.b(["\u0422\u0440\u0438\u0430\u043b 7 \u0434\u043d\u0435\u0439 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0432\u0441\u0451 \u2014 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0443\u0441\u043f\u0435\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0436\u0438\u0442\u044c \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043f\u0435\u0442\u043b\u044e.","\u0413\u043e\u0434\u043e\u0432\u043e\u0439 \u0442\u0430\u0440\u0438\u0444 \u043f\u0440\u043e\u0434\u0430\u0451\u0442\u0441\u044f \u043a\u0430\u043a \xab\u0432\u0435\u0441\u044c \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0433\u043e\u0434\u0430\xbb, \u043c\u0435\u0441\u044f\u0447\u043d\u044b\u0439 \u2014 \u0440\u044f\u0434\u043e\u043c \u0434\u043b\u044f \u043a\u043e\u043d\u0442\u0440\u0430\u0441\u0442\u0430.","\u0411\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u044b\u0439 \u0441\u043b\u043e\u0439 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u0438 \u043f\u043e\u0441\u043b\u0435 \u043e\u0442\u043a\u0430\u0437\u0430: \u043f\u043e\u0433\u043e\u0434\u0430 \u0434\u043d\u044f, \u043a\u0430\u0440\u0442\u0430, 1 \u0432\u043e\u043f\u0440\u043e\u0441 \u041a\u043e\u043c\u043f\u0430\u0441\u0443 \u2014 \u043c\u0430\u0433\u043d\u0438\u0442 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0434\u0430\u043b\u044c\u0448\u0435."],k)
o=A.b(["\u0413\u043e\u0434\u043e\u0432\u0430\u044f \u043f\u043e\u0434\u043f\u0438\u0441\u043a\u0430 \u0434\u0435\u0440\u0436\u0438\u0442 \u043f\u043e\u0434\u043f\u0438\u0441\u0447\u0438\u043a\u043e\u0432 \u043a\u0440\u0430\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u043c\u0435\u0441\u044f\u0447\u043d\u043e\u0439 (\u043f\u043e \u0431\u0435\u043d\u0447\u043c\u0430\u0440\u043a\u0430\u043c ~36% \u043f\u0440\u043e\u0442\u0438\u0432 ~7% \u0447\u0435\u0440\u0435\u0437 \u0433\u043e\u0434) \u2014 \u044d\u0442\u043e \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0430\u044f \u0431\u0430\u0437\u0430 rev-share.","\u041f\u0435\u0440\u0432\u044b\u0435 \u0432\u043e\u043b\u043d\u044b \u043f\u0440\u0438\u0434\u0443\u0442 \u0438\u0437 \u0432\u0430\u0448\u0438\u0445 \u0441\u043e\u0446\u0441\u0435\u0442\u0435\u0439 \u2014 \u0442\u0435, \u0443 \u043a\u043e\u0433\u043e \u043f\u0440\u043e\u0434\u0443\u043a\u0442 \u0443\u0436\u0435 \u043e\u043f\u043b\u0430\u0447\u0435\u043d, \u043f\u043e\u043f\u0430\u0434\u0430\u044e\u0442 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0441\u0440\u0430\u0437\u0443, \u043c\u0438\u043d\u0443\u044f \u044d\u0442\u043e\u0442 \u044d\u043a\u0440\u0430\u043d."],k)
o=A.qN(A.b(["\u0426\u0435\u043d\u044b \u2014 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440 \u0434\u043b\u044f \u043e\u0431\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u044f (\u0433\u043e\u0434 7 990 \u20bd \u2248 \u043a\u043b\u0443\u0431\u0443 \xab\u0421\u043c\u044b\u0441\u043b\u044b\xbb). \u041a\u0430\u043a\u0430\u044f \u043b\u043e\u0433\u0438\u043a\u0430 \u0446\u0435\u043d \u0440\u044f\u0434\u043e\u043c \u0441 \u043a\u043b\u0443\u0431\u043e\u043c?","\u041d\u0430\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0435: \u0431\u0443\u0434\u0443\u0442 \u043b\u0438 \u0435\u0436\u0435\u043d\u0435\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u044d\u0444\u0438\u0440\u044b \u0441 \u044d\u043a\u0441\u043f\u0435\u0440\u0442\u0430\u043c\u0438?","\u0415\u0436\u0435\u043c\u0435\u0441\u044f\u0447\u043d\u044b\u0435 \u044d\u0444\u0438\u0440\u044b \u0441 \u042e\u043b\u0438\u0435\u0439 \u2014 \u0432\u0445\u043e\u0434\u044f\u0442 \u0432 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0443?","\u0414\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u043c \u043b\u0438 \u0447\u0430\u0442\u044b \u0438 \u043a\u043e\u043c\u043c\u0443\u043d\u0438\u043a\u0430\u0446\u0438\u044e \u043c\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043d\u0438\u043a\u0430\u043c\u0438?"],k),B.eH,j,B.c5,"\u041f\u0435\u0439\u0432\u043e\u043b\u043b","\u041f\u0435\u0439\u0432\u043e\u043b\u043b: \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0433\u043e\u0434\u0430","\u042d\u043a\u0440\u0430\u043d \u043f\u043e\u0434\u043f\u0438\u0441\u043a\u0438 \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438: 7 \u0434\u043d\u0435\u0439 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e, \u0443\u043f\u043e\u0440 \u043d\u0430 \u0433\u043e\u0434\u043e\u0432\u043e\u0439 \u0442\u0430\u0440\u0438\u0444.",o)
j=A.b(["\u0413\u043b\u0430\u0432\u043d\u044b\u0439 \u0432\u0438\u0434\u0436\u0435\u0442 \u2014 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430: \u0442\u0435\u043c\u0430 \u043c\u0435\u0441\u044f\u0446\u0430, \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441, \u0440\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u0430\u0446\u0438\u0438 \u0438 \u043f\u0443\u043d\u043a\u0442\u044b \u2014 \u0432\u0438\u0434\u0435\u043e, \u0432\u0435\u0431\u0438\u043d\u0430\u0440, \u0437\u0430\u0434\u0430\u043d\u0438\u0435, \u043b\u0438\u0447\u043d\u0430\u044f \u0446\u0435\u043b\u044c. \u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u0435\u043b\u044c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u0433\u043e\u0434\u0430.","\u041a\u0430\u0436\u0434\u044b\u0439 \u043f\u0443\u043d\u043a\u0442 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0448\u0442\u043e\u0440\u043a\u043e\u0439: \u043f\u043e\u0441\u043c\u043e\u0442\u0440\u0435\u043b \u0432\u0438\u0434\u0435\u043e \u2192 \u043e\u0442\u043c\u0435\u0442\u0438\u043b \u2192 \u043f\u0443\u043d\u043a\u0442 \u0441\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f; \u0432\u0435\u0431\u0438\u043d\u0430\u0440\u044b \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u044e\u0442\u0441\u044f \u043f\u043e \u0434\u0430\u0442\u0430\u043c; \u0446\u0435\u043b\u044c \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u043f\u0438\u0448\u0435\u0442 \u0441\u0430\u043c.","\u041d\u0438\u0436\u0435 \u2014 \u0437\u0430\u0434\u0430\u043d\u0438\u0435 \u043e\u0442 \u041a\u043e\u043c\u043f\u0430\u0441\u0430 (\xab\u043f\u043e\u0434\u0443\u043c\u0430\u0439\u0442\u0435 \u043e\u0431 \u044d\u0442\u043e\u043c\xbb), \u043a\u0430\u0440\u0442\u0430 \u0434\u043d\u044f, \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430, \u0441\u0435\u0440\u0438\u044f \u0434\u043d\u0435\u0439 \u0438 \u0434\u043d\u0435\u0432\u043d\u0438\u043a."],k)
